scripts.postResponse:
rq.test('Status is success', function(){ rq.expect(rq.response.code).to.be.oneOf([200,201]); });
let json = {}; try { json = rq.response.json(); } catch(e) {}
const reference = json.reference || json.data?.reference || '';
const authUrl = json.authorization_url || json.data?.authorization_url || '';
rq.test('Reference exists', function(){ rq.expect(reference).to.be.a('string').and.not.empty; });
rq.test('Authorization URL exists', function(){ rq.expect(authUrl).to.be.a('string').and.not.empty; });
rq.collectionVariables.set('subscription_reference', reference);
